import React, { useState, useEffect } from 'react';
import axios from 'axios';
import io from 'socket.io-client';

// Настройка подключений
const API = axios.create({ baseURL: 'http://localhost:5000' });
const socket = io('http://localhost:5000');

function App() {
  const [isLogin, setIsLogin] = useState(true);
  const [user, setUser] = useState(null);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // Форма регистрации/входа
  const [formData, setFormData] = useState({
    email: '',
    username: '',
    displayName: '',
    password: '',
    login: ''
  });

  // Загружаем пользователей после входа
  useEffect(() => {
    if (user) {
      fetchUsers();
      socket.emit('user-online', user.id);
      
      socket.on('new-message', (message) => {
        if (selectedUser && message.senderId === selectedUser.id) {
          setMessages(prev => [...prev, message]);
        }
      });
    }

    return () => {
      socket.off('new-message');
    };
  }, [user, selectedUser]);

  const fetchUsers = async () => {
    try {
      const res = await API.get(`/api/users/${user.id}`);
      setUsers(res.data);
    } catch (err) {
      console.error('Ошибка загрузки пользователей:', err);
    }
  };

  const fetchMessages = async (otherUserId) => {
    try {
      // Для простоты пока заглушка
      setMessages([
        {
          id: 1,
          senderId: user.id,
          text: 'Привет!',
          createdAt: new Date().toISOString()
        },
        {
          id: 2,
          senderId: otherUserId,
          text: 'Здорово!',
          createdAt: new Date().toISOString()
        }
      ]);
    } catch (err) {
      console.error('Ошибка загрузки сообщений:', err);
    }
  };

  const sendMessage = () => {
    if (!newMessage.trim() || !selectedUser) return;

    const message = {
      id: Date.now(),
      senderId: user.id,
      text: newMessage,
      createdAt: new Date().toISOString()
    };

    setMessages(prev => [...prev, message]);
    setNewMessage('');

    socket.emit('send-message', {
      conversationId: `${user.id}-${selectedUser.id}`,
      senderId: user.id,
      receiverId: selectedUser.id,
      text: newMessage
    });
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    
    try {
      await API.post('/api/register', {
        email: formData.email,
        username: formData.username,
        displayName: formData.displayName,
        password: formData.password
      });
      
      setMessage('Регистрация успешна! Теперь войдите.');
      setFormData({ ...formData, email: '', username: '', displayName: '', password: '' });
      setIsLogin(true);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка регистрации');
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    
    try {
      const res = await API.post('/api/login', {
        login: formData.login,
        password: formData.password
      });
      
      setUser(res.data.user);
      setMessage(`Добро пожаловать, ${res.data.user.displayName}!`);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка входа');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setUsers([]);
    setSelectedUser(null);
    setMessages([]);
    socket.disconnect();
  };

  const selectUser = (otherUser) => {
    setSelectedUser(otherUser);
    fetchMessages(otherUser.id);
  };

  // Если пользователь не вошёл - показываем форму входа/регистрации
  if (!user) {
    return (
      <div style={{ maxWidth: '400px', margin: '50px auto', padding: '20px', fontFamily: 'Arial' }}>
        <h1 style={{ textAlign: 'center' }}>Chatty</h1>
        
        <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
          <button 
            onClick={() => setIsLogin(true)}
            style={{ 
              flex: 1, padding: '10px', 
              background: isLogin ? '#4CAF50' : '#f0f0f0',
              color: isLogin ? 'white' : 'black',
              border: 'none', 
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            Вход
          </button>
          <button 
            onClick={() => setIsLogin(false)}
            style={{ 
              flex: 1, padding: '10px',
              background: !isLogin ? '#4CAF50' : '#f0f0f0',
              color: !isLogin ? 'white' : 'black',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            Регистрация
          </button>
        </div>

        {error && (
          <div style={{ background: '#ffebee', color: '#c62828', padding: '10px', borderRadius: '5px', marginBottom: '20px' }}>
            {error}
          </div>
        )}

        {message && (
          <div style={{ background: '#e8f5e8', color: '#2e7d32', padding: '10px', borderRadius: '5px', marginBottom: '20px' }}>
            {message}
          </div>
        )}

        {isLogin ? (
          <form onSubmit={handleLogin}>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Email или Username:</label>
              <input
                type="text"
                value={formData.login}
                onChange={(e) => setFormData({...formData, login: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Пароль:</label>
              <input
                type="password"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <button 
              type="submit"
              style={{ width: '100%', padding: '10px', background: '#4CAF50', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
            >
              Войти
            </button>
          </form>
        ) : (
          <form onSubmit={handleRegister}>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Email:</label>
              <input
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Username:</label>
              <input
                type="text"
                value={formData.username}
                onChange={(e) => setFormData({...formData, username: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Имя (отображается):</label>
              <input
                type="text"
                value={formData.displayName}
                onChange={(e) => setFormData({...formData, displayName: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>Пароль:</label>
              <input
                type="password"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                style={{ width: '100%', padding: '8px', border: '1px solid #ddd', borderRadius: '4px' }}
                required
              />
            </div>
            <button 
              type="submit"
              style={{ width: '100%', padding: '10px', background: '#4CAF50', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
            >
              Зарегистрироваться
            </button>
          </form>
        )}
      </div>
    );
  }

  // Если пользователь вошёл - показываем мессенджер
  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'Arial' }}>
      {/* Левая панель - список пользователей */}
      <div style={{ width: '300px', borderRight: '1px solid #ddd', background: '#f8f9fa' }}>
        <div style={{ padding: '20px', borderBottom: '1px solid #ddd' }}>
          <h2 style={{ margin: '0 0 10px 0' }}>Chatty</h2>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ 
              width: '40px', height: '40px', 
              background: '#4CAF50', 
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
              fontWeight: 'bold'
            }}>
              {user.displayName[0]}
            </div>
            <div>
              <div><strong>{user.displayName}</strong></div>
              <div style={{ fontSize: '12px', color: '#666' }}>@{user.username}</div>
            </div>
            <button 
              onClick={handleLogout}
              style={{ 
                marginLeft: 'auto',
                padding: '5px 10px',
                background: '#f44336',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              Выйти
            </button>
          </div>
        </div>

        <div style={{ padding: '10px' }}>
          <input
            type="text"
            placeholder="Поиск пользователей..."
            style={{ 
              width: '100%', 
              padding: '8px', 
              border: '1px solid #ddd', 
              borderRadius: '20px',
              marginBottom: '20px'
            }}
          />
          
          <h3 style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#666' }}>Пользователи</h3>
          
          {users.map(otherUser => (
            <div
              key={otherUser.id}
              onClick={() => selectUser(otherUser)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
                padding: '10px',
                background: selectedUser?.id === otherUser.id ? '#e3f2fd' : 'transparent',
                borderRadius: '8px',
                cursor: 'pointer',
                marginBottom: '5px'
              }}
            >
              <div style={{
                width: '40px', height: '40px',
                background: '#9C27B0',
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'white'
              }}>
                {otherUser.displayName[0]}
              </div>
              <div>
                <div><strong>{otherUser.displayName}</strong></div>
                <div style={{ fontSize: '12px', color: '#666' }}>@{otherUser.username}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Правая панель - чат */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        {selectedUser ? (
          <>
            {/* Шапка чата */}
            <div style={{ 
              padding: '20px', 
              borderBottom: '1px solid #ddd',
              background: '#fff'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <div style={{
                  width: '40px', height: '40px',
                  background: '#9C27B0',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: 'white'
                }}>
                  {selectedUser.displayName[0]}
                </div>
                <div>
                  <h2 style={{ margin: 0 }}>{selectedUser.displayName}</h2>
                  <div style={{ fontSize: '12px', color: '#666' }}>@{selectedUser.username}</div>
                </div>
              </div>
            </div>

            {/* Сообщения */}
            <div style={{ 
              flex: 1, 
              padding: '20px', 
              overflow: 'auto',
              background: '#f5f5f5'
            }}>
              {messages.map(msg => (
                <div
                  key={msg.id}
                  style={{
                    display: 'flex',
                    justifyContent: msg.senderId === user.id ? 'flex-end' : 'flex-start',
                    marginBottom: '15px'
                  }}
                >
                  <div style={{
                    maxWidth: '60%',
                    padding: '10px 15px',
                    background: msg.senderId === user.id ? '#4CAF50' : '#fff',
                    color: msg.senderId === user.id ? 'white' : 'black',
                    borderRadius: '15px',
                    borderBottomRightRadius: msg.senderId === user.id ? '5px' : '15px',
                    borderBottomLeftRadius: msg.senderId === user.id ? '15px' : '5px'
                  }}>
                    <div>{msg.text}</div>
                    <div style={{ 
                      fontSize: '10px', 
                      marginTop: '5px',
                      color: msg.senderId === user.id ? 'rgba(255,255,255,0.8)' : '#999'
                    }}>
                      {new Date(msg.createdAt).toLocaleTimeString()}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Поле ввода */}
            <div style={{ 
              padding: '20px', 
              borderTop: '1px solid #ddd',
              background: '#fff'
            }}>
              <div style={{ display: 'flex', gap: '10px' }}>
                <input
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
                  placeholder="Напишите сообщение..."
                  style={{
                    flex: 1,
                    padding: '10px',
                    border: '1px solid #ddd',
                    borderRadius: '20px'
                  }}
                />
                <button
                  onClick={sendMessage}
                  style={{
                    padding: '10px 20px',
                    background: '#4CAF50',
                    color: 'white',
                    border: 'none',
                    borderRadius: '20px',
                    cursor: 'pointer'
                  }}
                >
                  Отправить
                </button>
              </div>
            </div>
          </>
        ) : (
          <div style={{ 
            flex: 1, 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            color: '#666'
          }}>
            Выберите пользователя для начала чата
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
